// ── Helpers ──────────────────────────────────────────────────────────────────
function val(node) {
    if (node && typeof node === 'object' && 'value' in node) return node.value;
    return (node === undefined) ? null : node;
}
function r2(v)       { return (v === null || v === undefined) ? null : Math.round(v * 100) / 100; }
function K2C(v)      { return v !== null ? r2(v - 273.15) : null; }
function J2Wh(v)     { return v !== null ? r2(v / 3600)   : null; }
function frac2pct(v) { return v !== null ? r2(v * 100)    : null; }
function rad2deg(v)  { return v !== null ? r2(v * 180 / Math.PI) : null; }
function m32L(v)     { return v !== null ? r2(v * 1000)   : null; }
function sec2min(v)  { return v !== null ? r2(v / 60)     : null; }
function sec2h(v)    { return v !== null ? r2(v / 3600)   : null; }
function C2A(v)      { return v !== null ? r2(v / 3600)   : null; }

const self  = msg.payload || {};
const elec  = self.electrical  || {};
const env   = self.environment || {};
const tanks = self.tanks       || {};
const nav   = self.navigation  || {};
const prop  = self.propulsion  || {};

// ── Solar / MPPT chargers ─────────────────────────────────────────────────────
const solar = {};
for (const [id, c] of Object.entries(elec.solar || {})) {
    if (typeof c !== 'object') continue;
    const pv = val(c.panelVoltage);
    const pc = val(c.panelCurrent);
    const pp = val(c.panelPower);
    solar[id] = {
        panelVoltage_V:   r2(pv),
        panelCurrent_A:   r2(pc),
        panelPower_W:     r2(pp ?? (pv !== null && pc !== null ? pv * pc : null)),
        outputVoltage_V:  r2(val(c.voltage)),
        outputCurrent_A:  r2(val(c.current)),
        outputPower_W:    r2(val(c.power)),
        yieldToday_Wh:    J2Wh(val(c.yieldToday)),
        yieldYesterday_Wh:J2Wh(val(c.yieldYesterday)),
        yieldTotal_Wh:    J2Wh(val(c.yieldTotal)),
        maxPowerToday_W:  r2(val(c.maxPowerToday)),
        controllerMode:   val(c.controllerMode),
        errorCode:        val(c.errorCode),
        chargeState:      val(c.chargeState),
        temperature_C:    K2C(val(c.temperature)),
    };
}

// ── Battery banks ─────────────────────────────────────────────────────────────
const batteries = {};
for (const [id, b] of Object.entries(elec.batteries || {})) {
    if (typeof b !== 'object') continue;
    const cap = b.capacity || {};
    batteries[id] = {
        voltage_V:           r2(val(b.voltage)),
        current_A:           r2(val(b.current)),
        power_W:             r2(val(b.power)),
        stateOfCharge_pct:   frac2pct(val(cap.stateOfCharge)),
        timeRemaining_min:   sec2min(val(cap.timeRemaining)),
        consumedAh:          C2A(val(cap.consumedCharge)),
        capacity_Ah:         C2A(val(cap.nominal)),
        temperature_C:       K2C(val(b.temperature)),
        midpointVoltage_V:   r2(val(b.midPointVoltage)),
        midpointDeviation_pct: frac2pct(val(b.midPointDeviationVoltage)),
        starterVoltage_V:    r2(val(b.starter?.voltage ?? b.starterVoltage)),
        chargeEfficiency_pct:frac2pct(val(b.chargeEfficiency)),
        lowVoltageAlarm:     val(b.lowVoltageAlarm),
        highVoltageAlarm:    val(b.highVoltageAlarm),
    };
}

// ── Inverter / Charger (MultiPlus, Quattro, Phoenix) ─────────────────────────
const inverters = {};
for (const [id, inv] of Object.entries(elec.inverter || {})) {
    if (typeof inv !== 'object') continue;
    const buildPhase = (phases) => {
        const out = {};
        for (const [ph, p] of Object.entries(phases || {})) {
            if (typeof p !== 'object') continue;
            out[ph] = {
                voltage_V:      r2(val(p.voltage)),
                current_A:      r2(val(p.current)),
                frequency_Hz:   r2(val(p.frequency)),
                power_W:        r2(val(p.power)),
                apparentPower_VA: r2(val(p.apparentPower)),
                powerFactor:    r2(val(p.powerFactor)),
            };
        }
        return out;
    };
    inverters[id] = {
        operatingMode:  val(inv.operatingMode),
        state:          val(inv.state),
        activeInput:    val(inv?.ac?.activeInput),
        dc: {
            voltage_V:  r2(val(inv?.dc?.voltage)),
            current_A:  r2(val(inv?.dc?.current)),
            power_W:    r2(val(inv?.dc?.power)),
        },
        acIn:  buildPhase(inv?.ac?.in),
        acOut: buildPhase(inv?.ac?.out),
    };
}

// ── AC Grid / Shore power ─────────────────────────────────────────────────────
const acGrid = {};
for (const [ph, p] of Object.entries(elec?.ac?.main || {})) {
    if (typeof p !== 'object') continue;
    acGrid[ph] = {
        voltage_V:    r2(val(p.voltage)),
        current_A:    r2(val(p.current)),
        frequency_Hz: r2(val(p.frequency)),
        power_W:      r2(val(p.power)),
        energy_kWh:   r2(val(p.energy) / 1000),
    };
}

// ── AC Output / Loads ─────────────────────────────────────────────────────────
const acLoads = {};
for (const [ph, p] of Object.entries(elec?.ac?.out || {})) {
    if (typeof p !== 'object') continue;
    acLoads[ph] = {
        voltage_V:    r2(val(p.voltage)),
        current_A:    r2(val(p.current)),
        frequency_Hz: r2(val(p.frequency)),
        power_W:      r2(val(p.power)),
    };
}

// ── Generator ─────────────────────────────────────────────────────────────────
const genset = {};
for (const [ph, p] of Object.entries(elec?.ac?.genset || {})) {
    if (typeof p !== 'object') continue;
    genset[ph] = {
        voltage_V:    r2(val(p.voltage)),
        current_A:    r2(val(p.current)),
        frequency_Hz: r2(val(p.frequency)),
        power_W:      r2(val(p.power)),
        runtime_h:    sec2h(val(p.runTime ?? p.runtime)),
        running:      val(p.running ?? p.state),
    };
}

// ── DC System ─────────────────────────────────────────────────────────────────
const dc = {
    systemVoltage_V:  r2(val(elec?.dc?.system?.voltage)),
    systemCurrent_A:  r2(val(elec?.dc?.system?.current)),
    systemPower_W:    r2(val(elec?.dc?.system?.power)),
};

// ── Tanks ─────────────────────────────────────────────────────────────────────
const tankData = {};
for (const [id, t] of Object.entries(tanks)) {
    if (typeof t !== 'object') continue;
    const level    = val(t.currentLevel);
    const capacity = val(t.capacity);
    tankData[id] = {
        type:        val(t.type),
        level_pct:   frac2pct(level),
        capacity_L:  m32L(capacity),
        remaining_L: (level !== null && capacity !== null) ? r2(level * capacity * 1000) : null,
    };
}

// ── Environment ───────────────────────────────────────────────────────────────
const environment = {
    inside: {
        temperature_C: K2C(val(env?.inside?.temperature)),
        humidity_pct:  frac2pct(val(env?.inside?.humidity)),
    },
    outside: {
        temperature_C: K2C(val(env?.outside?.temperature)),
        humidity_pct:  frac2pct(val(env?.outside?.humidity)),
        pressure_hPa:  r2((val(env?.outside?.pressure) ?? 0) / 100) || null,
    },
    water: {
        temperature_C: K2C(val(env?.water?.temperature)),
    },
    solar: {
        irradiance_Wm2: r2(val(env?.solar?.irradiance ?? env?.outside?.irradiance)),
    },
};

// ── Navigation / GPS ─────────────────────────────────────────────────────────
const position = val(nav?.position);
const navigation = {
    latitude:              position?.latitude  ?? null,
    longitude:             position?.longitude ?? null,
    speedOverGround_ms:    r2(val(nav?.speedOverGround)),
    courseOverGround_deg:  rad2deg(val(nav?.courseOverGround)),
    headingTrue_deg:       rad2deg(val(nav?.headingTrue)),
    headingMagnetic_deg:   rad2deg(val(nav?.headingMagnetic)),
    altitude_m:            r2(val(nav?.altitude ?? nav?.gnss?.antennaAltitude)),
    satellites:            val(nav?.gnss?.satellites),
    fixType:               val(nav?.gnss?.methodQuality ?? nav?.gnss?.type),
};

msg.payload = {
    timestamp: new Date().toISOString().replace('T', ' ').substring(0, 19),
    portalId: flow.get('portalId') || 'unknown',
    solar,
    batteries,
    inverters,
    acGrid,
    acLoads,
    genset,
    dc,
    tanks: tankData,
    environment,
    navigation,
};

return msg;

// ── InfluxDB v2 Line Protocol formatter ──────────────────────────────────────
// TOKEN: change 'INFLUX_TOKEN_HERE' here AND in docker-compose.yml AND
//        in grafana/provisioning/datasources/influxdb.yaml
const INFLUX_TOKEN = 'INFLUX_TOKEN_HERE';

// Nanosecond timestamp: Date.now() is ms; append 6 zeros to get ns
const tsNs = String(Date.now()) + '000000';

// Escape spaces, commas, equals in tag keys/values and field keys
function esc(s) {
    return String(s).replace(/[, =]/g, '\\$&');
}

// Return 'key=value,...' for all non-null numeric properties of obj
function numFields(obj) {
    return Object.entries(obj)
        .filter(([, v]) => v !== null && v !== undefined && typeof v === 'number')
        .map(([k, v]) => esc(k) + '=' + v)
        .join(',');
}

const lines = [];
const p = msg.payload;

// solar_charger — one line per charger ID
for (const [id, c] of Object.entries(p.solar || {})) {
    const fields = numFields(c);
    if (fields) lines.push('solar_charger,id=' + esc(id) + ' ' + fields + ' ' + tsNs);
}

// battery — one line per battery ID
for (const [id, b] of Object.entries(p.batteries || {})) {
    const fields = numFields(b);
    if (fields) lines.push('battery,id=' + esc(id) + ' ' + fields + ' ' + tsNs);
}

// inverter — dc voltage/current/power only, one line per inverter ID
for (const [id, inv] of Object.entries(p.inverters || {})) {
    const dc = inv.dc || {};
    const fields = numFields(dc);
    if (fields) lines.push('inverter,id=' + esc(id) + ' ' + fields + ' ' + tsNs);
}

// environment — flatten nested zone objects into a single line
const env = p.environment || {};
const envFields = [];
for (const [zone, vals] of Object.entries(env)) {
    if (vals && typeof vals === 'object') {
        for (const [key, v] of Object.entries(vals)) {
            if (v !== null && v !== undefined && typeof v === 'number') {
                envFields.push(esc(zone + '_' + key) + '=' + v);
            }
        }
    }
}
if (envFields.length) lines.push('environment ' + envFields.join(',') + ' ' + tsNs);

// tanks — one line per tank ID, tags: id, type
for (const [id, t] of Object.entries(p.tanks || {})) {
    const tagType = (t.type !== null && t.type !== undefined)
        ? ',type=' + esc(String(t.type)) : '';
    const fields = numFields({ level_pct: t.level_pct, remaining_L: t.remaining_L });
    if (fields) lines.push('tanks,id=' + esc(id) + tagType + ' ' + fields + ' ' + tsNs);
}

// navigation — single line with lat, lon, speed, satellites
const nav = p.navigation || {};
const navFields = numFields({
    lat:        nav.latitude,
    lon:        nav.longitude,
    speed:      nav.speedOverGround_ms,
    satellites: nav.satellites,
});
if (navFields) lines.push('navigation ' + navFields + ' ' + tsNs);

msg.payload = lines.join('\n');
msg.headers = {
    'Authorization': 'Token ' + INFLUX_TOKEN,
    'Content-Type':  'text/plain; charset=utf-8',
};
return msg;

// dbus-send stdout contains: variant string "abc123"
const match = (msg.payload || '').match(/string\s+"([a-f0-9A-F]+)"/i);
if (match) {
    const portalId = match[1].toLowerCase();
    flow.set('portalId', portalId);
    node.status({fill:'green', shape:'dot', text:'portalId: ' + portalId});
    node.log('Portal ID set: ' + portalId);
    msg.payload = portalId;
    return msg;
}
node.warn('D-Bus parse failed. Raw output: ' + msg.payload);
node.status({fill:'red', shape:'dot', text:'D-Bus parse failed'});
return null;

const portalId = flow.get('portalId');
msg.topic = 'R/' + portalId + '/system/0/Serial';
msg.payload = '';
return msg;

// topic format: N/{portalId}/solarcharger/{instanceId}/DeviceInstance
const parts = msg.topic.split('/');
const portalId = parts[1];
const instanceId = parts[3];
flow.set('portalId', portalId);
const chargers = flow.get('chargers') || [];
if (!chargers.includes(instanceId)) {
    chargers.push(instanceId);
    flow.set('chargers', chargers);
}
node.status({fill:'green', shape:'dot', text: `Found charger ${instanceId} on ${portalId}`});
return null; // don't pass message on

const portalId = flow.get('portalId');
msg.topic = 'R/' + portalId + '/solarcharger/+/DeviceInstance';
msg.payload = '';
return msg;

const parts = msg.topic.split('/');
const instanceId = parts[3];
const batteries = flow.get('batteries') || [];
if (!batteries.includes(instanceId)) {
    batteries.push(instanceId);
    flow.set('batteries', instanceId);
}
node.status({fill:'green', shape:'dot', text: `Found battery ${instanceId}`});
return null;

node.log('[MPPT] Building OFF command...');
node.status({fill:'yellow', shape:'ring', text:'Building OFF command...'});

const portalId = flow.get('portalId');
const chargers = flow.get('chargers') || [];

node.log('[MPPT] portalId=' + portalId + ' chargers=' + JSON.stringify(chargers));

if (!portalId) {
    node.warn('[MPPT] Aborted — portalId not discovered yet');
    node.status({fill:'red', shape:'dot', text:'No portalId — run discovery first'});
    return null;
}
if (chargers.length === 0) {
    node.warn('[MPPT] Aborted — no chargers discovered yet');
    node.status({fill:'red', shape:'dot', text:'No chargers found'});
    return null;
}

const topic = 'W/' + portalId + '/solarcharger/' + chargers[0] + '/Mode';
const payload = JSON.stringify({value: 4});
node.log('[MPPT] OFF command ready: topic=' + topic + ' payload=' + payload);
node.status({fill:'orange', shape:'dot', text:'OFF → ' + chargers.join(',')});

msg.topic = topic;
msg.payload = payload;
return msg;

node.log('[MPPT] Building ON command...');
const portalId = flow.get('portalId');
const chargers = flow.get('chargers') || [];
const topic = 'W/' + portalId + '/solarcharger/' + chargers[0] + '/Mode';
const payload = JSON.stringify({value: 1});
node.log('[MPPT] ON command ready: topic=' + topic + ' payload=' + payload);
node.status({fill:'blue', shape:'dot', text:'ON → ' + chargers.join(',')});
msg.topic = topic;
msg.payload = payload;
return msg;
